                <button key={v} onClick={()=>setCatF(v)} style={{padding:"7px 12px",border:"none",borderRadius:8,background:catF===v?"#0F172A":"transparent",color:catF===v?"#fff":"#64748B",fontWeight:700,cursor:"pointer",fontSize:".78rem",fontFamily:"inherit",transition:"all .15s"}}>{l}</button>
