                <button key={v} onClick={()=>setLvlF(v)} style={{padding:"7px 12px",border:"none",borderRadius:8,background:lvlF===v?"#0F172A":"transparent",color:lvlF===v?"#fff":"#64748B",fontWeight:700,cursor:"pointer",fontSize:".78rem",fontFamily:"inherit",transition:"all .15s"}}>{l}</button>
